
class Toleration {final String? key; final String? operator; final String? value; final String? effect; final int? tolerationSeconds; Toleration({this.key, this.operator, this.value, this.effect, this.tolerationSeconds}); factory Toleration.fromJson(Map<String, dynamic> json) {return Toleration(key: json['key'], operator: json['operator'], value: json['value'], effect: json['effect'], tolerationSeconds: json['tolerationSeconds']);} Map<String, dynamic> toJson() {return {if (key != null) 'key' : key, if (operator != null) 'operator' : operator, if (value != null) 'value' : value, if (effect != null) 'effect' : effect, if (tolerationSeconds != null) 'tolerationSeconds' : tolerationSeconds};}}
